def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 5):
                    base = np.sin(ratio * b / (a + 0.5)) ** 3
                    damp = np.exp(-(ratio - a)/ (b + 1))
                    priority += (base * damp) / (a + b)
            priority += (np.cosh(ratio) - np.log1p(ratio)) * np.sin(ratio * 2) ** 2
            if (i + int(item)) % 2 == 0:
                priority *= np.tanh(item / (bin_cap + 1))
            else:
                priority /= (1 + np.abs(np.cos(i * ratio)))
        elif 5 < ratio <= 8:
            for x in range(1, 10):
                accum = 0
                for y in range(1, 5):
                    val = ((ratio - 4.5) ** y) / (y ** 2 + 0.7) * np.sin(x * y * ratio)
                    accum += val
                priority += np.tanh(accum) * np.exp(-x / 7)
            priority += np.log(ratio + 0.5) * 7
            if bin_cap < item * 1.5:
                priority += np.sqrt(item * bin_cap) * 3
            else:
                priority -= np.exp(-ratio / 2)
        elif 2 < ratio <= 5:
            s = 0
            for n in range(1, 15):
                factor = ((ratio - 2) ** n) / (n + 1.5)
                trig = np.cos(n * ratio * 1.3) - np.sin(n * ratio * 0.7)
                s += factor * trig
            priority = s * np.tanh(ratio) + np.log1p(bin_cap) * 4.5
            if ratio < 3:
                priority += np.sin(i * ratio) * 2.2
            else:
                priority -= np.cos(i * ratio / 2) * 1.7
        elif 1 <= ratio <= 2:
            s = 0
            for m in range(1, 20):
                base = ((2 - ratio) ** m) / (m * m + 0.8)
                trig = np.tanh(np.sin(m * ratio * item)) - np.cos(m * ratio / (item + 0.1))
                s += base * trig
            priority = s + np.exp(-bin_cap / (item + 0.1)) * 6
            if bin_cap > item:
                priority += np.log1p(bin_cap / item) * 3.5
            for idx in range(1, 6):
                if (i + idx) % 5 == 0:
                    priority += np.sin(ratio * idx * 1.7) * 0.9
                else:
                    priority -= np.cos(ratio * idx * 1.7) * 0.9
        elif 0.5 <= ratio < 1:
            s = 0
            for u in range(1, 25):
                base = ((1 - ratio) ** u) / (u * 1.1 + 0.2)
                trig = np.sin(u * item * ratio * 0.6) + np.cos(u * ratio * i * 0.9)
                s += base * trig
            priority = s * np.sin(ratio * 3) + np.exp(-item / (bin_cap + 0.5)) * 5
            if (i * int(item)) % 7 == 0:
                priority *= np.log1p(bin_cap + item)
            else:
                priority /= (1 + np.sqrt(bin_cap + 2))
        elif 0.2 <= ratio < 0.5:
            s = 0
            for w in range(1, 30):
                decay = np.exp(-w / 15)
                base = ((0.5 - ratio) ** w) / (w * 2 + 1)
                trig = np.cos(w * ratio * 2.1) * np.sin(w * item * 1.1)
                s += decay * base * trig
            priority = s + (bin_cap / (item + 0.1)) ** 0.75
            if int(item * 0.9) % 3 == 0:
                priority += np.log1p(bin_cap * item) * 2
            else:
                priority -= np.sqrt(bin_cap) * 1.5
        else:
            s = 0
            for z in range(1, 35):
                factor = ((0.2 - ratio) ** z) / (z * 3 + 2)
                trig = np.sin(z * item * ratio * 0.75) + np.cos(z * i * 0.6)
                s += factor * trig
            priority = s + np.exp(-ratio * 3) * 7
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-bin_cap / (item + 0.5)) * 5
        if bin_cap < item * 0.7:
            priority += np.tanh(item / (bin_cap + 0.3)) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-ratio * 5) * 3
        for l in range(1, 6):
            if (i + l) % 4 == 0:
                priority += np.sin(ratio * l * i) * 0.4
            else:
                priority -= np.cos(ratio * l * i) * 0.4
            if (i * l) % 5 == 0:
                priority += np.tanh(l * ratio / (i + 1)) * 0.3
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
